<?php
namespace Tests\Feature;
use App\Jobs\ExpireGraceSubscriptionsJob;use App\Jobs\MarkOverdueInvoicesJob;use App\Models\{Invoice,Payment,Plan,Project,Subscription,Task,TaskAttachment,User,Workspace};use App\Services\Billing\{BillingService,PlanLimitService,SubscriptionService};use Illuminate\Foundation\Testing\RefreshDatabase;use Tests\TestCase;
class Phase5BillingTest extends TestCase{use RefreshDatabase;private function workspace(array $plan=[]):array{$user=User::create(['name'=>'Owner','email'=>uniqid().'@example.com','password'=>'x','status'=>'active']);$w=Workspace::create(['name'=>'Acme','slug'=>uniqid('acme-'),'status'=>'active','owner_id'=>$user->id,'currency'=>'USD']);$w->users()->attach($user->id,['role_key'=>'workspace_owner','status'=>'active','joined_at'=>now()]);$p=Plan::create(array_merge(['name'=>'Starter','slug'=>uniqid('starter-'),'monthly_price'=>10,'currency'=>'USD','user_limit'=>1,'project_limit'=>1,'storage_limit_mb'=>1,'ai_monthly_quota'=>0,'is_public'=>true,'is_active'=>true],$plan));$s=Subscription::create(['workspace_id'=>$w->id,'plan_id'=>$p->id,'status'=>'active','current_period_start'=>today(),'current_period_end'=>today()->addMonth(),'billing_cycle'=>'monthly']);return [$w,$p,$s,$user];}public function test_trial_subscription_created_on_signup_still_works():void{Plan::create(['name'=>'Starter','slug'=>'starter','monthly_price'=>19,'currency'=>'USD','user_limit'=>5,'project_limit'=>3,'storage_limit_mb'=>500,'is_public'=>true,'is_active'=>true]);$this->post('/register',['name'=>'Owner','email'=>'owner@example.com','password'=>'password123','password_confirmation'=>'password123','company_name'=>'Acme Team','workspace_slug'=>'acme-team'])->assertRedirect('/onboarding');$this->assertDatabaseHas('subscriptions',['status'=>'trial']);}public function test_invoice_can_be_generated_and_manual_payment_marks_paid():void{[$w,$p,$s]=$this->workspace();$billing=app(BillingService::class);$invoice=$billing->createInvoiceForSubscription($s);$payment=Payment::create(['workspace_id'=>$w->id,'invoice_id'=>$invoice->id,'subscription_id'=>$s->id,'payment_number'=>$billing->generatePaymentNumber(),'gateway'=>'manual','status'=>'successful','currency'=>'USD','amount'=>$invoice->total,'paid_at'=>now()]);$billing->markInvoicePaid($invoice,$payment);$this->assertSame('paid',$invoice->refresh()->status);$this->assertEquals(0,(float)$invoice->amount_due);}public function test_subscription_can_change_plan():void{[$w]=$this->workspace();$new=Plan::create(['name'=>'Pro','slug'=>'pro-'.uniqid(),'monthly_price'=>20,'currency'=>'USD','is_public'=>true,'is_active'=>true]);$sub=app(SubscriptionService::class)->changePlan($w,$new);$this->assertSame($new->id,$sub->refresh()->plan_id);}public function test_limits_block_users_projects_storage_and_ai():void{[$w]= $this->workspace();$limits=app(PlanLimitService::class);$this->assertFalse($limits->canAddUser($w));Project::create(['workspace_id'=>$w->id,'name'=>'One','status'=>'active']);$this->assertFalse($limits->canCreateProject($w));$task=Task::create(['workspace_id'=>$w->id,'task_number'=>'T-1','title'=>'Task','priority'=>'medium','status'=>'todo','created_by'=>$w->owner_id]);TaskAttachment::create(['workspace_id'=>$w->id,'task_id'=>$task->id,'uploaded_by'=>null,'file_name'=>'a','original_name'=>'a','file_path'=>'a','file_disk'=>'local','mime_type'=>'text/plain','file_size'=>1024*1024,'attachment_type'=>'general']);$this->assertFalse($limits->canUseStorage($w,1));$this->assertFalse($limits->canUseAi($w));}public function test_overdue_and_grace_jobs_update_subscription_and_workspace():void{[$w,$p,$s]=$this->workspace();Invoice::create(['workspace_id'=>$w->id,'subscription_id'=>$s->id,'invoice_number'=>'INV-X','status'=>'issued','currency'=>'USD','total'=>10,'amount_due'=>10,'due_date'=>today()->subDay()]);app(MarkOverdueInvoicesJob::class)->handle(app(SubscriptionService::class));$this->assertSame('overdue',Invoice::first()->status);$s->refresh()->update(['grace_ends_at'=>today()->subDay()]);app(ExpireGraceSubscriptionsJob::class)->handle(app(SubscriptionService::class));$this->assertSame('suspended',$s->refresh()->status);$this->assertSame('suspended',$w->refresh()->status);}public function test_invoice_numbers_and_payment_numbers_are_unique():void{$billing=app(BillingService::class);$this->assertNotSame($billing->generateInvoiceNumber(),$billing->generateInvoiceNumber());$this->assertNotSame($billing->generatePaymentNumber(),$billing->generatePaymentNumber());}}
